#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        for(int i=0;i<n;i++){
            if(i) printf(" ");
            printf("%d", 251 + i);
        }
        if(T) printf("\n");
    }
    return 0;
}

